219→    private final ReaderActions.DataRequestedListener mDataRequestedListener =
220→            new ReaderActions.DataRequestedListener() {
221→                @Override
222→                public void onRequestData() {
223→                    // skip if update is already in progress
224→                    if (isUpdating()) {
225→                        return;
226→                    }
227→
228→                    // request older posts unless we already have the max # to show
229→                    switch (getPostListType()) {
230→                        case TAG_FOLLOWED:
231→                            // fall through to TAG_PREVIEW
232→                        case TAG_PREVIEW:
233→                            if (ReaderPostTable.getNumPostsWithTag(mCurrentTag)
234→                                < ReaderConstants.READER_MAX_POSTS_TO_DISPLAY) {
235→                                // request older posts
236→                                updatePostsWithTag(getCurrentTag(), UpdateAction.REQUEST_OLDER);
237→                                mReaderTracker.track(AnalyticsTracker.Stat.READER_INFINITE_SCROLL);
238→                            }
239→                            break;
240→
241→                        case BLOG_PREVIEW:
242→                            int numPosts;
243→                            if (mCurrentFeedId != 0) {
244→                                numPosts = ReaderPostTable.getNumPostsInFeed(mCurrentFeedId);
245→                            } else {
246→                                numPosts = ReaderPostTable.getNumPostsInBlog(mCurrentBlogId);
247→                            }
248→                            if (numPosts < ReaderConstants.READER_MAX_POSTS_TO_DISPLAY) {
249→                                updatePostsInCurrentBlogOrFeed(UpdateAction.REQUEST_OLDER);
250→                                mReaderTracker.track(AnalyticsTracker.Stat.READER_INFINITE_SCROLL);
251→                            }
252→                            break;
253→
254→                        case SEARCH_RESULTS:
255→                            ReaderTag searchTag = ReaderUtils.getTagForSearchQuery(mCurrentSearchQuery);
256→                            int offset = ReaderPostTable.getNumPostsWithTag(searchTag);
257→                            if (offset < ReaderConstants.READER_MAX_POSTS_TO_DISPLAY) {
258→                                updatePostsInCurrentSearch(offset);
259→                                mReaderTracker.track(AnalyticsTracker.Stat.READER_INFINITE_SCROLL);
260→                            }
261→                            break;
262→                    }
263→                }
264→            };
